def predict_next_frame(frame, action, xy=None):
    """
    Simple deterministic rule inferred from the data:
      * All actions (ACTION1‑ACTION5) flip the left‑most 0 in the top row to 1.
      * ACTION6 also flips a single cell in the top row, but the column depends
        on the click coordinates. Observed mappings are stored in `click_to_col`.
      * No other cells ever change.
    """
    # make a mutable copy of the frame
    new_frame = [row[:] for row in frame]

    def flip_leftmost_zero():
        for c, v in enumerate(new_frame[0]):
            if v == 0:
                new_frame[0][c] = 1
                break

    # click → column mapping for ACTION6 (observed examples)
    click_to_col = {
        (62, 21): 38,
        (6, 37): 26,
        (54, 23): 61,
    }

    if action == "ACTION6":
        if xy is not None and xy in click_to_col:
            new_frame[0][click_to_col[xy]] = 1
        else:
            flip_leftmost_zero()
    elif action.startswith("ACTION"):
        # ACTION1‑ACTION5 (and any other ACTION) use the generic rule
        flip_leftmost_zero()
    # ACTION7 or unknown actions leave the frame unchanged

    return new_frame
